namespace muna {

    class Configuration final {
    public:
        Configuration() = default;

        explicit Configuration(const std::filesystem::path& resource_dir) :
            manifest_(load_manifest(resource_dir))
        { }

        FXNAcceleration acceleration() const noexcept { return acceleration_; }

        void set_acceleration(FXNAcceleration acceleration) noexcept { acceleration_ = acceleration; }

        void* device() const noexcept { return device_; }

        template<typename T>
        T* device() const noexcept { return static_cast<T*>(device_); }

        template<typename T>
        void set_device(T* device) noexcept { device_ = static_cast<void*>(device); }

        std::filesystem::path resource(const std::string& hash) const {
            if (!manifest_.contains(hash))
                throw std::out_of_range("Resource not found: " + hash);
            return manifest_.at(hash);
        }

        void add_resource(const std::filesystem::path& path) {
            std::string key = path.filename().string();
            manifest_[key] = path;
        }

    private:
        std::unordered_map<std::string, std::filesystem::path> manifest_;
        FXNAcceleration acceleration_ = FXN_ACCELERATION_CPU;
        void* device_ = nullptr;

        static std::unordered_map<std::string, std::filesystem::path> load_manifest(const std::filesystem::path& resource_dir) {
            std::unordered_map<std::string, std::filesystem::path> manifest;
            if (!std::filesystem::exists(resource_dir))
                return manifest;
            for (const auto& entry : std::filesystem::directory_iterator(resource_dir))
                if (entry.is_regular_file()) {
                    std::string key = entry.path().filename().string();
                    manifest[key] = entry.path();
                }
            return manifest;
        }
    };
}

namespace muna {

    class TensorStorage {
    public:

        explicit TensorStorage(size_t byte_size) : 
            data_(new uint8_t[byte_size + PADDING_BYTES], std::default_delete<uint8_t[]>{}),
            byte_size_(byte_size) { }

        TensorStorage(
            const std::shared_ptr<TensorStorage>& parent,
            size_t offset,
            size_t byte_size
        ) : data_(parent, parent->data() + offset), byte_size_(byte_size) { }

        TensorStorage(
            uint8_t* external_data,
            size_t byte_size,
            std::function<void()> deleter = nullptr
        ) : data_(
            external_data,
            [deleter](uint8_t*) { if (deleter) deleter(); }
        ), byte_size_(byte_size) { }

        uint8_t* data() const { return data_.get(); }

        size_t byte_size() const { return byte_size_; }

        long use_count() const { return data_.use_count(); }

    private:
        std::shared_ptr<uint8_t> data_;
        size_t byte_size_;

        static constexpr size_t PADDING_BYTES = 128;
    };
}

