namespace builtins {

    struct iter_string final {

        std::vector<std::string> operator()(
            const std::string& input_string
        ) const {
            FXN_ASSERT(
                simdutf::validate_utf8(input_string.c_str(), input_string.size()),
                "Cannot iterate over invalid UTF-8 string: {}",
                input_string
            );
            size_t char_count = simdutf::count_utf8(input_string.c_str(), input_string.size());
            std::vector<char32_t> codepoints(char_count);
            size_t converted = simdutf::convert_utf8_to_utf32(
                input_string.c_str(),
                input_string.size(),
                codepoints.data()
            );
            std::vector<std::string> characters(converted);
            std::transform(
                codepoints.begin(),
                codepoints.begin() + converted,
                characters.begin(),
                [](const char32_t &codepoint) {
                    char utf8_char[5] = {0}; 
                    size_t utf8_len = simdutf::convert_utf32_to_utf8(&codepoint, 1, utf8_char);
                    return std::string(utf8_char, utf8_len);
                }
            );
            return characters;
        }
    };
}

namespace tensor {

    struct getitem_vector_slice final {

        template<typename T>
        std::vector<T> operator()(
            const std::vector<T>& vec,
            const muna::slice& slice
        ) const {
            auto indices = slice.indices(static_cast<int>(vec.size()));
            std::vector<T> result(indices.size());
            std::transform(
                indices.begin(),
                indices.end(),
                result.begin(),
                [&vec](int32_t idx) { return vec[idx]; }
            );
            return result;
        }
    };
}

namespace _operator {

    struct add_vector final {

        template<typename T>
        std::vector<T> operator()(const std::vector<T>& lhs, const std::vector<T>& rhs) const {
            std::vector<T> result;
            result.reserve(lhs.size() + rhs.size());
            result.insert(result.end(), lhs.begin(), lhs.end());
            result.insert(result.end(), rhs.begin(), rhs.end());
            return result;
        }
    };
}

namespace muna {

    class PixelBuffer {
    public:

        enum class PixelFormat {
            Unknown = 0,
            R8 = 1,
            RGB888 = 3,
            RGBA8888 = 4,
            BGRA8888 = 36,
        };

        PixelBuffer() :
            width_(0), height_(0), format_(PixelFormat::Unknown),
            row_stride_(0), offset_(0)
        { }

        PixelBuffer(
            size_t width,
            size_t height,
            PixelFormat format,
            uint8_t* data,
            size_t row_stride
        ) : width_(width), height_(height), format_(format), row_stride_(row_stride), offset_(0) {
            data_ = std::make_shared<TensorStorage>(data, height_ * row_stride_);
        }

        PixelBuffer(
            size_t width,
            size_t height,
            PixelFormat format,
            size_t row_stride
        ) : width_(width), height_(height), format_(format), row_stride_(row_stride), offset_(0) {
            data_ = std::make_shared<TensorStorage>(height_ * row_stride_);
        }

        PixelBuffer(
            size_t width,
            size_t height,
            PixelFormat format,
            std::shared_ptr<TensorStorage> storage,
            size_t row_stride,
            size_t offset = 0
        ) : width_(width), height_(height), format_(format), data_(storage), row_stride_(row_stride), offset_(offset) {
            FXN_ASSERT(
                storage->byte_size() >= height_ * row_stride_,
                "TensorStorage size is too small for given dimensions"
            );
        }

        uint8_t* data() const { return data_->data() + offset_; }

        size_t width() const { return width_; }

        size_t height() const { return height_; }

        size_t row_stride() const { return row_stride_; }

        PixelFormat format() const { return format_; }

        size_t channels() const {
            switch (format_) {
                case PixelFormat::R8:       return 1;
                case PixelFormat::RGB888:   return 3;
                case PixelFormat::RGBA8888: return 4;
                case PixelFormat::BGRA8888: return 4;
                default:                    return 0;
            }
        }

        std::shared_ptr<TensorStorage> storage() const { return data_; }

    private:
        std::shared_ptr<TensorStorage> data_;
        size_t width_;
        size_t height_;
        size_t row_stride_;
        PixelFormat format_;
        size_t offset_;
    };
}

