namespace numpy {

    struct array final {

        muna::Tensor operator()(const std::vector<float>& vec) const {
            std::vector<double> converted_vec(vec.begin(), vec.end());
            muna::Tensor tensor(FXN_DTYPE_FLOAT64, { vec.size() });
            std::copy(converted_vec.begin(), converted_vec.end(), tensor.data<double>());
            return tensor;
        }

        muna::Tensor operator()(const std::vector<int32_t>& vec) const {
            return operator()(vec, numpy::int64{ });
        }

        muna::Tensor operator()(const std::vector<bool>& vec) const {
            muna::Tensor tensor(FXN_DTYPE_BOOL, {vec.size()});
            std::transform(
                vec.begin(),
                vec.end(),
                tensor.data<bool>(),
                [](bool b) { return b; }
            );
            return tensor;
        }

        muna::Tensor operator()(const std::vector<std::vector<uint8_t>>& vec) const {
            if (vec.empty())
                return muna::Tensor(FXN_DTYPE_INT64, {0, 0});
            size_t rows = vec.size();
            size_t cols = vec[0].size();
            muna::Tensor tensor(FXN_DTYPE_INT64, { rows, cols });
            int64_t* data = tensor.data<int64_t>();
            for (size_t i = 0; i < rows; ++i) {
                FXN_ASSERT(
                    vec[i].size() == cols,
                    "All rows must have the same length. Row 0 has {} elements, but row {} has {} elements",
                    cols, i, vec[i].size()
                );
                std::transform(
                    vec[i].begin(),
                    vec[i].end(), 
                    data + i * cols,
                    [](uint8_t val) { return static_cast<int64_t>(val); }
                );
            }
            return tensor;
        }

        muna::Tensor operator()(
            const std::vector<float>& vec,
            numpy::float32 dtype
        ) const {
            muna::Tensor tensor(FXN_DTYPE_FLOAT32, { vec.size() });
            std::copy(vec.begin(), vec.end(), tensor.data<float>());
            return tensor;
        }

        muna::Tensor operator()(
            const std::vector<int32_t>& vec,
            numpy::float32 dtype
        ) const {
            muna::Tensor tensor(FXN_DTYPE_FLOAT32, { vec.size() });
            std::transform(
                vec.begin(),
                vec.end(),
                tensor.data<float>(),
                [](int32_t i) { return static_cast<float>(i); }
            );
            return tensor;
        }

        muna::Tensor operator()(
            const std::vector<int32_t>& vec,
            numpy::int32 dtype
        ) const {
            muna::Tensor tensor(FXN_DTYPE_INT32, { vec.size() });
            std::copy(vec.begin(), vec.end(), tensor.data<int32_t>());
            return tensor;
        }

        muna::Tensor operator()(
            const int32_t& item,
            numpy::int64 dtype
        ) const {
            muna::Tensor tensor(FXN_DTYPE_INT64, { });
            tensor.data<int64_t>()[0] = item;
            return tensor;
        }

        muna::Tensor operator()(
            const std::vector<int32_t>& vec,
            numpy::int64 dtype
        ) const {
            std::vector<int64_t> converted_vec(vec.begin(), vec.end());
            muna::Tensor tensor(FXN_DTYPE_INT64, { vec.size() });
            std::copy(converted_vec.begin(), converted_vec.end(), tensor.data<int64_t>());
            return tensor;
        }

        muna::Tensor operator()(
            const std::vector<int32_t>& vec,
            const std::string& dtype
        ) const {
            if (dtype == "float32") return impl<float>(vec);
            if (dtype == "float64") return impl<double>(vec);
            if (dtype == "int8")    return impl<int8_t>(vec);
            if (dtype == "int16")   return impl<int16_t>(vec);
            if (dtype == "int32")   return impl<int32_t>(vec);
            if (dtype == "int64")   return impl<int64_t>(vec);
            if (dtype == "uint8")   return impl<uint8_t>(vec);
            if (dtype == "uint16")  return impl<uint16_t>(vec);
            if (dtype == "uint32")  return impl<uint32_t>(vec);
            if (dtype == "uint64")  return impl<uint64_t>(vec);
            if (dtype == "bool")    return impl<bool>(vec);
            FXN_ASSERT(
                false,
                "numpy.array with int32 vector: unsupported dtype '{}'",
                dtype
            );
        }

        muna::Tensor operator()(
            const std::vector<std::vector<float>>& vec,
            numpy::float32 dtype
        ) const {
            if (vec.empty())
                return muna::Tensor(FXN_DTYPE_FLOAT32, {0, 0});
            size_t rows = vec.size();
            size_t cols = vec[0].size();
            muna::Tensor tensor(FXN_DTYPE_FLOAT32, { rows, cols });
            float* data = tensor.data<float>();
            for (size_t i = 0; i < rows; ++i)
                std::copy(vec[i].begin(), vec[i].end(), data + i * cols);
            return tensor;
        }

        muna::Tensor operator()(
            const std::vector<std::vector<int32_t>>& vec,
            numpy::float32 dtype
        ) const {
            if (vec.empty())
                return muna::Tensor(FXN_DTYPE_FLOAT32, { 0, 0 });
            size_t rows = vec.size();
            size_t cols = vec[0].size();
            muna::Tensor tensor(FXN_DTYPE_FLOAT32, { rows, cols });
            float* data = tensor.data<float>();
            for (size_t i = 0; i < rows; ++i)
                std::transform(
                    vec[i].begin(),
                    vec[i].end(),
                    data + i * cols,
                    [](int32_t val) { return static_cast<float>(val); }
                );
            return tensor;
        }

        muna::Tensor operator()(
            const std::vector<std::vector<int32_t>>& vec,
            numpy::int32 dtype
        ) const {
            if (vec.empty()) {
                return muna::Tensor(FXN_DTYPE_INT32, {0, 0});
            }
            size_t rows = vec.size();
            size_t cols = vec[0].size();
            muna::Tensor tensor(FXN_DTYPE_INT32, { rows, cols });
            int32_t* data = tensor.data<int32_t>();
            for (size_t i = 0; i < rows; ++i)
                std::copy(vec[i].begin(), vec[i].end(), data + i * cols);
            return tensor;
        }

        muna::Tensor operator()(
            const std::vector<std::vector<int32_t>>& vec,
            numpy::int64 dtype
        ) const {
            if (vec.empty())
                return muna::Tensor(FXN_DTYPE_INT64, { 0, 0 });
            size_t rows = vec.size();
            size_t cols = vec[0].size();
            muna::Tensor tensor(FXN_DTYPE_INT64, { rows, cols });
            int64_t* data = tensor.data<int64_t>();
            for (size_t i = 0; i < rows; ++i)
                std::transform(
                    vec[i].begin(),
                    vec[i].end(),
                    data + i * cols,
                    [](int32_t val) { return static_cast<int64_t>(val); }
                );
            return tensor;
        }

        muna::Tensor operator()(
            const std::vector<std::vector<float>>& vec,
            const std::string& dtype
        ) const {
            if (dtype == "float32") return impl<float, float>(vec);
            if (dtype == "float64") return impl<double, float>(vec);
            if (dtype == "int8")    return impl<int8_t, float>(vec);
            if (dtype == "int16")   return impl<int16_t, float>(vec);
            if (dtype == "int32")   return impl<int32_t, float>(vec);
            if (dtype == "int64")   return impl<int64_t, float>(vec);
            if (dtype == "uint8")   return impl<uint8_t, float>(vec);
            if (dtype == "uint16")  return impl<uint16_t, float>(vec);
            if (dtype == "uint32")  return impl<uint32_t, float>(vec);
            if (dtype == "uint64")  return impl<uint64_t, float>(vec);
            if (dtype == "bool")    return impl<bool, float>(vec);
            FXN_ASSERT(
                false,
                "numpy.array with vector<vector<float>> and dtype '{}': unsupported dtype",
                dtype
            );
        }

        muna::Tensor operator()(const muna::PixelBuffer& image) const {
            return muna::Tensor(
                image.storage(),
                FXN_DTYPE_UINT8,
                { image.height(), image.width(), image.channels() }
            );
        }

    private:

        template<typename T, typename InputType>
        static muna::Tensor impl(const std::vector<InputType>& vec) {
            muna::Tensor tensor(muna::Tensor::dtype<T>(), { vec.size() });
            if constexpr (std::is_same_v<T, InputType>) {
                std::copy(vec.begin(), vec.end(), tensor.data<T>());
            } else {
                std::transform(
                    vec.begin(),
                    vec.end(),
                    tensor.data<T>(),
                    [](InputType val) { return static_cast<T>(val); }
                );
            }
            return tensor;
        }

        template <typename OutputType, typename InputType>
        static muna::Tensor impl(const std::vector<std::vector<InputType>>& vec) {
            if (vec.empty())
                return muna::Tensor(muna::Tensor::dtype<OutputType>(), { 0, 0 });
            size_t rows = vec.size();
            size_t cols = vec[0].size();
            muna::Tensor tensor(muna::Tensor::dtype<OutputType>(), { rows, cols });
            OutputType* data = tensor.data<OutputType>();
            for (size_t i = 0; i < rows; ++i) {
                FXN_ASSERT(
                    vec[i].size() == cols,
                    "All rows must have the same length. Row 0 has {} elements, but row {} has {} elements",
                    cols, 
                    i, 
                    vec[i].size()
                );
                if constexpr (std::is_same_v<InputType, OutputType>) {
                    std::copy(vec[i].begin(), vec[i].end(), data + i * cols);
                } else {
                    std::transform(
                        vec[i].begin(),
                        vec[i].end(),
                        data + i * cols,
                        [](InputType val) { return static_cast<OutputType>(val); }
                    );
                }
            }
            return tensor;
        }
    };
}

