    struct getitem_tensor_1d_null final {

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            std::nullptr_t indexer
        ) const {
            (void)indexer;
            auto original_shape = tensor.shape();
            std::vector<size_t> new_shape;
            new_shape.reserve(original_shape.size() + 1);
            new_shape.push_back(1);  
            new_shape.insert(new_shape.end(), original_shape.begin(), original_shape.end());
            muna::Tensor result(tensor.dtype(), new_shape);
            std::memcpy(result.data(), tensor.data(), tensor.byte_size());
            return result;
        }

    };
