namespace tensor {

    struct getitem_tensor_1d_int final {

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            const int32_t index
        ) const {
            auto shape = tensor.shape();
            FXN_ASSERT(
                !shape.empty(),
                "Cannot index a 0-d tensor"
            );
            std::ptrdiff_t idx = index;
            if (idx < 0)
                idx += static_cast<std::ptrdiff_t>(shape[0]);
            FXN_ASSERT(
                idx >= 0 && static_cast<size_t>(idx) < shape[0],
                "Index {} is out of bounds for tensor with shape[0] = {}",
                index,
                shape[0]
            );
            std::vector<size_t> result_shape(shape.begin() + 1, shape.end());
            auto strides = tensor.strides();
            std::vector<size_t> result_strides(strides.begin() + 1, strides.end());
            size_t element_offset = tensor.storage_offset() + static_cast<size_t>(idx) * strides[0];
            return muna::Tensor(
                tensor.storage(),
                tensor.dtype(),
                result_shape,
                result_strides,
                element_offset
            );
        }
    };
}

