namespace tensor {

    struct squeeze final {

        muna::Tensor operator()(const muna::Tensor& tensor) {
            std::vector<size_t> shape;
            std::copy_if(
                tensor.shape().begin(),
                tensor.shape().end(),
                std::back_inserter(shape),
                [](auto x) { return x != 1; }
            );
            muna::Tensor result(tensor.dtype(), shape);
            memcpy(result.data(), tensor.data(), tensor.byte_size());
            return result;
        }

        muna::Tensor operator()(const muna::Tensor& tensor, int32_t index) {
            const auto& shape = tensor.shape();
            size_t rank = shape.size();
            FXN_ASSERT(
                rank > 0,
                "Cannot squeeze a 0-dim tensor."
            );
            index = index < 0 ? static_cast<int32_t>(rank) + index : index;
            if (shape[index] != 1)
                return tensor;
            std::vector<size_t> new_shape;
            for (size_t i = 0; i < rank; ++i)
                if (static_cast<int32_t>(i) != index)
                    new_shape.push_back(shape[i]);
            muna::Tensor result(tensor.dtype(), new_shape);
            memcpy(result.data(), tensor.data(), tensor.byte_size());
            return result;
        }
    };
}

