namespace tensor {

    struct add_tensor_scalar_xt final {

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            const float scalar
        ) const {
            auto dtype = tensor.dtype();
            auto promoted_dtype = muna::Tensor::promote(dtype, FXN_DTYPE_FLOAT32);
            switch (promoted_dtype) {
                case FXN_DTYPE_FLOAT32: return add_tensor_scalar<float>(tensor, scalar);
                case FXN_DTYPE_FLOAT64: return add_tensor_scalar<double>(tensor, static_cast<double>(scalar));
                default: FXN_ASSERT(
                    false,
                    "Failed to perform tensor addition because promoted data type is not supported: {}",
                    promoted_dtype
                );
            }
        }

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            const int32_t scalar
        ) const {
            auto dtype = tensor.dtype();
            switch (dtype) {
                case FXN_DTYPE_FLOAT32: return add_tensor_scalar_preserve_dtype<float>(tensor, scalar);
                case FXN_DTYPE_FLOAT64: return add_tensor_scalar_preserve_dtype<double>(tensor, scalar);
                case FXN_DTYPE_INT8:    return add_tensor_scalar_preserve_dtype<int8_t>(tensor, scalar);
                case FXN_DTYPE_INT16:   return add_tensor_scalar_preserve_dtype<int16_t>(tensor, scalar);
                case FXN_DTYPE_INT32:   return add_tensor_scalar_preserve_dtype<int32_t>(tensor, scalar);
                case FXN_DTYPE_INT64:   return add_tensor_scalar_preserve_dtype<int64_t>(tensor, scalar);
                case FXN_DTYPE_UINT8:   return add_tensor_scalar_preserve_dtype<uint8_t>(tensor, scalar);
                case FXN_DTYPE_UINT16:  return add_tensor_scalar_preserve_dtype<uint16_t>(tensor, scalar);
                case FXN_DTYPE_UINT32:  return add_tensor_scalar_preserve_dtype<uint32_t>(tensor, scalar);
                case FXN_DTYPE_UINT64:  return add_tensor_scalar_preserve_dtype<uint64_t>(tensor, scalar);
                case FXN_DTYPE_BOOL:    return add_tensor_scalar<int64_t>(tensor, static_cast<int64_t>(scalar));
                default: FXN_ASSERT(
                    false,
                    "Failed to perform tensor addition because data type is not supported: {}",
                    dtype
                );
            }
        }

    private:

        template<typename T>
        static muna::Tensor add_tensor_scalar(
            const muna::Tensor& tensor,
            T scalar
        ) {
            auto array = tensor_to_xt_array_cast<T>(tensor);
            xt::xarray<T> result = array + scalar;
            return xt_array_to_tensor(result);
        }

        template<typename T>
        static muna::Tensor add_tensor_scalar_preserve_dtype(
            const muna::Tensor& tensor,
            int32_t scalar
        ) {
            auto array = tensor_to_xt_array<T>(tensor);
            xt::xarray<T> result = array + static_cast<T>(scalar);
            return xt_array_to_tensor(result);
        }
    };
}

namespace numpy {

    struct ones_like final {

        muna::Tensor operator()(const muna::Tensor& tensor) const {
            switch (tensor.dtype()) {
                case FXN_DTYPE_FLOAT32:     return impl<float>(tensor);
                case FXN_DTYPE_FLOAT64:     return impl<double>(tensor);
                case FXN_DTYPE_INT8:        return impl<int8_t>(tensor);
                case FXN_DTYPE_INT16:       return impl<int16_t>(tensor);
                case FXN_DTYPE_INT32:       return impl<int32_t>(tensor);
                case FXN_DTYPE_INT64:       return impl<int64_t>(tensor);
                case FXN_DTYPE_UINT8:       return impl<uint8_t>(tensor);
                case FXN_DTYPE_UINT16:      return impl<uint16_t>(tensor);
                case FXN_DTYPE_UINT32:      return impl<uint32_t>(tensor);
                case FXN_DTYPE_UINT64:      return impl<uint64_t>(tensor);
                case FXN_DTYPE_BOOL:        return impl<bool>(tensor);
                default: FXN_ASSERT(
                    false,
                    "Failed to create ones_like because of unsupported tensor data type: {}",
                    tensor.dtype()
                );
            }
        }

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            numpy::int64 dtype_
        ) const {
            return impl<int64_t>(tensor);
        }

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            numpy::float32 dtype_
        ) const {
            return impl<float>(tensor);
        }

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            numpy::float64 dtype_
        ) const {
            return impl<double>(tensor);
        }

    private:

        template<typename T>
        static muna::Tensor impl(const muna::Tensor& tensor) {
            FXNDtype dtype = muna::Tensor::dtype<T>();
            auto tensor_shape = tensor.shape<size_t>();
            muna::Tensor result(dtype, tensor_shape);
            T* data = result.data<T>();
            size_t total_size = result.numel();
            std::fill(data, data + total_size, static_cast<T>(1));
            return result;
        }
    };
}

namespace muna {

    class range_view : public std::ranges::view_interface<range_view> {
    public:

        range_view() = default;

        explicit range_view(int32_t stop) : start_(0), stop_(stop), step_(stop < 0 ? -1 : 1) { }

        range_view(
            int32_t start,
            int32_t stop
        ) : start_(start), stop_(stop), step_(stop < start ? -1 : 1) { }

        range_view(
            int32_t start,
            int32_t stop,
            int32_t step
        ) : start_(start), stop_(stop), step_(step) {
            if (step_ == 0)
                throw std::invalid_argument("step cannot be zero");
        }

        auto begin() const {
            return iterator(start_, step_);
        }

        auto end() const {
            return iterator(stop_, step_);
        }

        bool empty() const {
            return (step_ > 0) ? (start_ >= stop_) : (start_ <= stop_);
        }

        int32_t start() const {
            return start_;
        }

        int32_t stop() const {
            return stop_;
        }

        int32_t step() const {
            return step_;
        }

    private:
        int32_t start_{};
        int32_t stop_{};
        int32_t step_{1};

        class iterator {
        private:
            int32_t current_{};
            int32_t step_{};
            bool is_forward_{};

        public:
            using iterator_category = std::input_iterator_tag;
            using difference_type = std::ptrdiff_t;
            using value_type = int32_t;
            using pointer = int32_t*;
            using reference = int32_t;

            iterator() = default;

            iterator(
                int32_t current,
                int32_t step
            ) : current_(current), step_(step), is_forward_(step > 0) {}

            reference operator*() const { return current_; }

            iterator& operator++() {
                current_ += step_;
                return *this;
            }

            iterator operator++(int) {
                iterator tmp = *this;
                ++*this;
                return tmp;
            }

            bool operator==(const iterator& other) const {
                if (is_forward_)
                    return current_ >= other.current_;
                else
                    return current_ <= other.current_;
            }
        };
    };
}

