namespace tensor {

    struct getitem_tensor_3d_slice_int_slice_xt final {

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            const std::tuple<muna::slice, int32_t, muna::slice>& index
        ) const {
            const auto& slice1 = std::get<0>(index);
            const int32_t int_idx = std::get<1>(index);
            const auto& slice2 = std::get<2>(index);

            auto shape = tensor.shape();
            FXN_ASSERT(
                shape.size() >= 3,
                "Cannot index tensor because tensor is {}d but 3d index was provided.",
                shape.size()
            );

            int32_t normalized_idx = int_idx;
            if (normalized_idx < 0) {
                normalized_idx += static_cast<int32_t>(shape[1]);
            }
            FXN_ASSERT(
                normalized_idx >= 0 && normalized_idx < static_cast<int32_t>(shape[1]),
                "Cannot index tensor because index {} is out of bounds for dimension 1 with size {}",
                int_idx,
                shape[1]
            );

            switch (tensor.dtype()) {
                case FXN_DTYPE_FLOAT32:     return slice_tensor<float>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_FLOAT64:     return slice_tensor<double>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_INT8:        return slice_tensor<int8_t>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_INT16:       return slice_tensor<int16_t>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_INT32:       return slice_tensor<int32_t>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_INT64:       return slice_tensor<int64_t>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_UINT8:       return slice_tensor<uint8_t>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_UINT16:      return slice_tensor<uint16_t>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_UINT32:      return slice_tensor<uint32_t>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_UINT64:      return slice_tensor<uint64_t>(tensor, slice1, normalized_idx, slice2);
                case FXN_DTYPE_BOOL:        return slice_tensor<bool>(tensor, slice1, normalized_idx, slice2);
                default: FXN_ASSERT(
                    false,
                    "Failed to slice tensor because of unsupported tensor data type: {}",
                    tensor.dtype()
                );
            }
        }

    private:

        template <typename T>
        muna::Tensor slice_tensor(
            const muna::Tensor& tensor,
            const muna::slice& slice1,
            int32_t int_idx,
            const muna::slice& slice2
        ) const {
            auto xt_tensor = tensor_to_xt_array<T>(tensor);
            auto shape = tensor.shape();

            auto range1 = slice_to_xt_range(slice1, static_cast<int>(shape[0]));
            auto range2 = slice_to_xt_range(slice2, static_cast<int>(shape[2]));

            auto sliced = xt::view(xt_tensor, range1, int_idx, range2);

            return xt_array_to_tensor(sliced);
        }
    };
}

namespace numpy {

    struct argmax_xt final {

        muna::Tensor operator()(const muna::Tensor& tensor) const {
            switch (tensor.dtype()) {
                case FXN_DTYPE_FLOAT32:     return impl(tensor_to_xt_array<float>(tensor));
                case FXN_DTYPE_FLOAT64:     return impl(tensor_to_xt_array<double>(tensor));
                case FXN_DTYPE_INT8:        return impl(tensor_to_xt_array<int8_t>(tensor));
                case FXN_DTYPE_INT16:       return impl(tensor_to_xt_array<int16_t>(tensor));
                case FXN_DTYPE_INT32:       return impl(tensor_to_xt_array<int32_t>(tensor));
                case FXN_DTYPE_INT64:       return impl(tensor_to_xt_array<int64_t>(tensor));
                case FXN_DTYPE_UINT8:       return impl(tensor_to_xt_array<uint8_t>(tensor));
                case FXN_DTYPE_UINT16:      return impl(tensor_to_xt_array<uint16_t>(tensor));
                case FXN_DTYPE_UINT32:      return impl(tensor_to_xt_array<uint32_t>(tensor));
                case FXN_DTYPE_UINT64:      return impl(tensor_to_xt_array<uint64_t>(tensor));
                default: FXN_ASSERT(
                    false,
                    "Failed to perform argmax because of unsupported tensor data type: {}",
                    tensor.dtype()
                );
            }
        }

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            const int32_t axis
        ) const {
            return operator()(tensor, axis, false);
        }

        muna::Tensor operator()(
            const muna::Tensor& tensor,
            const int32_t axis,
            const bool keepdims
        ) const {
            int real_dim = axis < 0 ? static_cast<int>(tensor.dims()) + axis : axis;
            FXN_ASSERT(
                real_dim >= 0 && real_dim < tensor.dims(),
                "Failed to perform argmax on {}d tensor because axis is out of range: {}",
                tensor.dims(),
                real_dim
            );
            switch (tensor.dtype()) {
                case FXN_DTYPE_FLOAT32:     return impl(tensor_to_xt_array<float>(tensor), real_dim, keepdims);
                case FXN_DTYPE_FLOAT64:     return impl(tensor_to_xt_array<double>(tensor), real_dim, keepdims);
                case FXN_DTYPE_INT8:        return impl(tensor_to_xt_array<int8_t>(tensor), real_dim, keepdims);
                case FXN_DTYPE_INT16:       return impl(tensor_to_xt_array<int16_t>(tensor), real_dim, keepdims);
                case FXN_DTYPE_INT32:       return impl(tensor_to_xt_array<int32_t>(tensor), real_dim, keepdims);
                case FXN_DTYPE_INT64:       return impl(tensor_to_xt_array<int64_t>(tensor), real_dim, keepdims);
                case FXN_DTYPE_UINT8:       return impl(tensor_to_xt_array<uint8_t>(tensor), real_dim, keepdims);
                case FXN_DTYPE_UINT16:      return impl(tensor_to_xt_array<uint16_t>(tensor), real_dim, keepdims);
                case FXN_DTYPE_UINT32:      return impl(tensor_to_xt_array<uint32_t>(tensor), real_dim, keepdims);
                case FXN_DTYPE_UINT64:      return impl(tensor_to_xt_array<uint64_t>(tensor), real_dim, keepdims);
                default: FXN_ASSERT(
                    false,
                    "Failed to perform argmax because of unsupported tensor data type: {}",
                    tensor.dtype()
                );
            }
        }

    private:

        template <class E>
        muna::Tensor impl( 
            const E& tensor,
            int axis,
            bool keepdims
        ) const {
            xt::xarray<int64_t> indices = xt::argmax(tensor, axis);
            if (!keepdims)
                return xt_array_to_tensor(indices);
            auto expanded_shape = tensor.shape();
            expanded_shape[axis] = 1;
            xt::xarray<int64_t> reshaped_indices = xt::reshape_view(indices, expanded_shape);
            return xt_array_to_tensor(reshaped_indices);
        }

        template <class E>
        muna::Tensor impl(const E& tensor) const {
            auto flattened = xt::flatten(tensor);
            size_t max_idx = xt::argmax(flattened)(0);  
            muna::Tensor result(FXN_DTYPE_INT64, {});  
            *result.data<int64_t>() = static_cast<int64_t>(max_idx);
            return result;
        }
    };
}

