    struct bytes_ final {

        std::vector<std::byte> operator()(const std::vector<int32_t>& vec) const {
            FXN_ASSERT(
                std::all_of(vec.begin(), vec.end(), [](int32_t val) {
                    return val >= 0 && val < 256;
                }),
                "bytes() values must be in range [0, 255]"
            );
            std::vector<std::byte> result(vec.size());
            std::transform(
                vec.begin(), vec.end(),
                result.begin(),
                [](int32_t val) { return static_cast<std::byte>(val); }
            );
            return result;
        }
    };
